/*
 * exports.map — linker version script for xrm_mind_port
 * Copyright 2026 STARGA, Inc.
 *
 * Controls which symbols are externally visible on the final ELF.
 * Everything not in the `global:` list is forced LOCAL, including
 * the entire STARGA MIND runtime, the governance kernel, the
 * evidence-chain internals, and the sealed XRM FFI thunk.
 *
 * If you find yourself wanting to add a symbol here, don't. The
 * public surface is an API, not a debugging aid.
 */

XRM_MIND_PORT_0_1 {
    global:
        /* CLI entry point only. */
        xrm_mind_port_main;

        /* Machine-readable bench output (stable across versions). */
        xrm_mind_port_run_sweep;
        xrm_mind_port_version;

        /* Seal verification result — read-only getter. */
        xrm_mind_port_seal_ok;

    local:
        /* Everything else is hidden. Explicit deny-list below for
         * symbols we absolutely never want to leak, even by accident. */
        kernel_*;
        invariant_*;
        gov9_*;
        verify_blob_seal*;
        xrm_reflect*;
        dispatch*;
        mind_only_path*;
        evidence_chain_*;
        evidence_root_*;
        clock_*;
        attest_run*;
        bench_one*;
        replay_verify*;
        Q16_16_*;
        Hash256_*;
        spec_hash_*;
        fixed_point_*;
        mind_runtime_*;
        mind_rt_*;
        mindc_*;
        _mind_source_*;
        _mind_debug_*;
        get_source*;
        *;
};
